-- Create standard_document_templates table with proper structure
CREATE TABLE standard_document_templates (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL UNIQUE,
  description TEXT,
  example TEXT,
  is_default BOOLEAN NOT NULL DEFAULT true,
  is_editable BOOLEAN NOT NULL DEFAULT true, 
  is_addable BOOLEAN NOT NULL DEFAULT true,
  document_type TEXT NOT NULL DEFAULT 'Standard',
  created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now(),
  updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now()
);

-- Enable RLS
ALTER TABLE standard_document_templates ENABLE ROW LEVEL SECURITY;

-- Create policies for standard document templates
CREATE POLICY "Standard templates are viewable by everyone" 
ON standard_document_templates 
FOR SELECT 
USING (true);

CREATE POLICY "Only super admins can modify standard templates" 
ON standard_document_templates 
FOR ALL 
USING (is_admin_user())
WITH CHECK (is_admin_user());

